unit lipdecide;

{$mode objfpc}{$H+}

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math; {for ArcCos, Sqrt, Abs, Power, Log10}

{--- Utility: six-significant-digit comparison --------------------------------}
function REALCOMPARE(A, B: real): COMPTYPE;
var
  s, diff: real;
  e: integer;
  tol: real;
begin
  if A = B then exit(EQ);
  s := Max(Abs(A), Abs(B));
  if s = 0.0 then exit(EQ);
  e := Floor(Log10(s));
  tol := 0.5 * Power(10.0, e - 5); {half-ULP at the 6th significant digit}
  diff := A - B;
  if Abs(diff) <= tol then exit(EQ)
  else if diff < 0.0 then exit(LT)
  else exit(GT);
end;

{--- Local geometry helpers ----------------------------------------------------}

function dist_pts(i, j: integer): real; inline;
var dx, dy: real;
begin
  dx := X[j] - X[i];
  dy := Y[j] - Y[i];
  dist_pts := Sqrt(dx*dx + dy*dy);
end;

function tri_area2(i, j, k: integer): real; inline;
{returns twice the triangle area (absolute)}
var ax, ay, bx, by: real;
begin
  ax := X[j] - X[i]; ay := Y[j] - Y[i];
  bx := X[k] - X[i]; by := Y[k] - Y[i];
  tri_area2 := Abs(ax*by - ay*bx);
end;

function tri_area(i, j, k: integer): real; inline;
begin
  tri_area := 0.5 * tri_area2(i, j, k);
end;

function angle_at(i, j, k: integer; out defined: boolean): real;
{returns angle in radians at vertex j between points i-j-k in [0, PI];
 defined=false if either leg has zero length}
var ux, uy, vx, vy, du, dv, dotv, c: real;
begin
  ux := X[i] - X[j]; uy := Y[i] - Y[j];
  vx := X[k] - X[j]; vy := Y[k] - Y[j];
  du := Sqrt(ux*ux + uy*uy);
  dv := Sqrt(vx*vx + vy*vy);
  if (REALCOMPARE(du, 0.0) = EQ) or (REALCOMPARE(dv, 0.0) = EQ) then begin
    defined := false;
    angle_at := 0.0;
    exit;
  end;
  defined := true;
  dotv := ux*vx + uy*vy;
  c := dotv / (du*dv);
  if c > 1.0 then c := 1.0 else if c < -1.0 then c := -1.0;
  angle_at := ArcCos(c);
end;

function point_line_distance(px, py, ax, ay, bx, by: real): real; inline;
{distance from point P to infinite line through A and B; if A=B, returns |P-A|}
var dx, dy, num, den: real;
begin
  dx := bx - ax; dy := by - ay;
  den := Sqrt(dx*dx + dy*dy);
  if REALCOMPARE(den, 0.0) = EQ then begin
    point_line_distance := Sqrt( (px-ax)*(px-ax) + (py-ay)*(py-ay) );
    exit;
  end;
  num := Abs( dy*(px-ax) - dx*(py-ay) );
  point_line_distance := num / den;
end;

function min_enclosing_circle_radius(i, j, k: integer): real;
{Minimal circle radius that contains points i, j, k (on or inside).}
var a, b, c, area2: real;
begin
  a := dist_pts(j, k);
  b := dist_pts(i, k);
  c := dist_pts(i, j);
  area2 := tri_area2(i, j, k);
  {Check for collinear or obtuse/right triangles}
  if (REALCOMPARE(a*a + b*b, c*c) <> GT) or
     (REALCOMPARE(b*b + c*c, a*a) <> GT) or
     (REALCOMPARE(c*c + a*a, b*b) <> GT) or
     (REALCOMPARE(area2, 0.0) = EQ) then
  begin
    {If any angle >= 90 degrees or area ~ 0: minimal circle is with diameter max side}
    if REALCOMPARE(a, b) = GT then begin
      if REALCOMPARE(a, c) = GT then
        min_enclosing_circle_radius := 0.5 * a
      else
        min_enclosing_circle_radius := 0.5 * c;
    end else begin
      if REALCOMPARE(b, c) = GT then
        min_enclosing_circle_radius := 0.5 * b
      else
        min_enclosing_circle_radius := 0.5 * c;
    end;
  end
  else begin
    {acute triangle: use circumradius R = abc / (4 * area)}
    min_enclosing_circle_radius := (a*b*c) / (2.0 * area2);
  end;
end;

function quadrant_of(xv, yv: real): integer; inline;
begin
  if REALCOMPARE(yv, 0.0) = GT then begin
    if REALCOMPARE(xv, 0.0) <> LT then quadrant_of := 1 else quadrant_of := 2;
  end else if REALCOMPARE(yv, 0.0) = LT then begin
    {on negative y-axis: priority to quadrant III}
    if REALCOMPARE(xv, 0.0) <> GT then quadrant_of := 3 else quadrant_of := 4;
  end else begin
    {y == 0: on x-axis; priority I for x>=0, II for x<0}
    if REALCOMPARE(xv, 0.0) <> LT then quadrant_of := 1 else quadrant_of := 2;
  end;
end;

{--- Individual LIC evaluators -------------------------------------------------}

function lic1: boolean;
var i: integer;
begin
  lic1 := false;
  if NUMPOINTS < 2 then exit; {by type, NUMPOINTS>=2}
  for i := 1 to NUMPOINTS-1 do begin
    if REALCOMPARE(dist_pts(i, i+1), PARAMETERS.LENGTH1) = GT then begin
      lic1 := true; exit;
    end;
  end;
end;

function lic2: boolean;
var i: integer; r: real;
begin
  lic2 := false;
  if NUMPOINTS < 3 then exit;
  for i := 1 to NUMPOINTS-2 do begin
    r := min_enclosing_circle_radius(i, i+1, i+2);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then begin
      lic2 := true; exit;
    end;
  end;
end;

function lic3: boolean;
var i: integer; ang: real; def: boolean; thresh: real;
begin
  lic3 := false;
  if NUMPOINTS < 3 then exit;
  thresh := globals.PI - PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS-2 do begin
    ang := angle_at(i, i+1, i+2, def);
    if def and ((REALCOMPARE(ang, thresh) = LT) or (REALCOMPARE(ang, globals.PI + PARAMETERS.EPSILON) = GT)) then begin
      lic3 := true; exit;
    end;
  end;
end;

function lic4: boolean;
var i: integer; a: real;
begin
  lic4 := false;
  if NUMPOINTS < 3 then exit;
  for i := 1 to NUMPOINTS-2 do begin
    a := tri_area(i, i+1, i+2);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then begin
      lic4 := true; exit;
    end;
  end;
end;

function lic5: boolean;
var i, j, q, startq: integer; present: array[1..4] of boolean; count: integer;
begin
  lic5 := false;
  if NUMPOINTS < PARAMETERS.Q_PTS then exit;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do begin
    for q := 1 to 4 do present[q] := false;
    for j := i to i + PARAMETERS.Q_PTS - 1 do begin
      startq := quadrant_of(X[j], Y[j]);
      present[startq] := true;
    end;
    count := 0;
    for q := 1 to 4 do if present[q] then Inc(count);
    if count > PARAMETERS.QUADS then begin
      lic5 := true; exit;
    end;
  end;
end;

function lic6: boolean;
var i: integer;
begin
  lic6 := false;
  if NUMPOINTS < 2 then exit;
  for i := 1 to NUMPOINTS-1 do begin
    if REALCOMPARE(X[i+1] - X[i], 0.0) = LT then begin
      lic6 := true; exit;
    end;
  end;
end;

function lic7: boolean;
var i, j, last: integer; d, maxd: real;
begin
  lic7 := false;
  if NUMPOINTS < 3 then exit;
  if PARAMETERS.N_PTS > NUMPOINTS then exit;
  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do begin
    last := i + PARAMETERS.N_PTS - 1;
    maxd := 0.0;
    if (REALCOMPARE(X[last], X[i]) = EQ) and (REALCOMPARE(Y[last], Y[i]) = EQ) then begin
      for j := i to last do begin
        d := dist_pts(i, j);
        if REALCOMPARE(d, maxd) = GT then maxd := d;
      end;
    end else begin
      for j := i to last do begin
        d := point_line_distance(X[j], Y[j], X[i], Y[i], X[last], Y[last]);
        if REALCOMPARE(d, maxd) = GT then maxd := d;
      end;
    end;
    if REALCOMPARE(maxd, PARAMETERS.DIST) = GT then begin
      lic7 := true; exit;
    end;
  end;
end;

function lic8: boolean;
var i, j: integer;
begin
  lic8 := false;
  if NUMPOINTS < 3 then exit;
  if PARAMETERS.K_PTS > NUMPOINTS - 2 then exit;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do begin
    j := i + PARAMETERS.K_PTS + 1;
    if REALCOMPARE(dist_pts(i, j), PARAMETERS.LENGTH1) = GT then begin
      lic8 := true; exit;
    end;
  end;
end;

function lic9: boolean;
var i, j, k: integer; r: real;
begin
  lic9 := false;
  if NUMPOINTS < 5 then exit;
  if (PARAMETERS.A_PTS + PARAMETERS.B_PTS > NUMPOINTS - 3) then exit;
  for i := 1 to NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS) - 2 do begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := min_enclosing_circle_radius(i, j, k);
    if REALCOMPARE(r, PARAMETERS.RADIUS1) = GT then begin
      lic9 := true; exit;
    end;
  end;
end;

function lic10: boolean;
var i, j, k: integer; ang: real; def: boolean; lowth, highth: real;
begin
  lic10 := false;
  if NUMPOINTS < 5 then exit;
  if (PARAMETERS.C_PTS + PARAMETERS.D_PTS > NUMPOINTS - 3) then exit;
  lowth := globals.PI - PARAMETERS.EPSILON;
  highth := globals.PI + PARAMETERS.EPSILON;
  for i := 1 to NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS) - 2 do begin
    j := i + PARAMETERS.C_PTS + 1;
    k := j + PARAMETERS.D_PTS + 1;
    ang := angle_at(i, j, k, def);
    if def and ((REALCOMPARE(ang, lowth) = LT) or (REALCOMPARE(ang, highth) = GT)) then begin
      lic10 := true; exit;
    end;
  end;
end;

function lic11: boolean;
var i, j, k: integer; a: real;
begin
  lic11 := false;
  if NUMPOINTS < 5 then exit;
  if (PARAMETERS.E_PTS + PARAMETERS.F_PTS > NUMPOINTS - 3) then exit;
  for i := 1 to NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS) - 2 do begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    a := tri_area(i, j, k);
    if REALCOMPARE(a, PARAMETERS.AREA1) = GT then begin
      lic11 := true; exit;
    end;
  end;
end;

function lic12: boolean;
var i, j: integer;
begin
  lic12 := false;
  if NUMPOINTS < 3 then exit;
  if PARAMETERS.G_PTS > NUMPOINTS - 2 then exit;
  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do begin
    j := i + PARAMETERS.G_PTS + 1;
    if REALCOMPARE(X[j] - X[i], 0.0) = LT then begin
      lic12 := true; exit;
    end;
  end;
end;

function lic13: boolean;
var i, j: integer; longok, shortok: boolean; d: real;
begin
  lic13 := false;
  if NUMPOINTS < 3 then exit;
  if PARAMETERS.K_PTS > NUMPOINTS - 2 then exit;
  longok := false; shortok := false;
  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do begin
    j := i + PARAMETERS.K_PTS + 1;
    d := dist_pts(i, j);
    if (not longok) and (REALCOMPARE(d, PARAMETERS.LENGTH1) = GT) then longok := true;
    if (not shortok) and (REALCOMPARE(d, PARAMETERS.LENGTH2) = LT) then shortok := true;
    if longok and shortok then begin lic13 := true; exit; end;
  end;
end;

function lic14: boolean;
var i, j, k: integer; r: real; part1, part2: boolean;
begin
  lic14 := false;
  if NUMPOINTS < 5 then exit;
  if (PARAMETERS.A_PTS + PARAMETERS.B_PTS > NUMPOINTS - 3) then exit;
  part1 := false; part2 := false;
  for i := 1 to NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS) - 2 do begin
    j := i + PARAMETERS.A_PTS + 1;
    k := j + PARAMETERS.B_PTS + 1;
    r := min_enclosing_circle_radius(i, j, k);
    if (not part1) and (REALCOMPARE(r, PARAMETERS.RADIUS1) = GT) then part1 := true;
    if (not part2) and (REALCOMPARE(r, PARAMETERS.RADIUS2) <> GT) then part2 := true; {r <= R2}
    if part1 and part2 then begin lic14 := true; exit; end;
  end;
end;

function lic15: boolean;
var i, j, k: integer; a: real; bigok, smallok: boolean;
begin
  lic15 := false;
  if NUMPOINTS < 5 then exit;
  if (PARAMETERS.E_PTS + PARAMETERS.F_PTS > NUMPOINTS - 3) then exit;
  bigok := false; smallok := false;
  for i := 1 to NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS) - 2 do begin
    j := i + PARAMETERS.E_PTS + 1;
    k := j + PARAMETERS.F_PTS + 1;
    a := tri_area(i, j, k);
    if (not bigok) and (REALCOMPARE(a, PARAMETERS.AREA1) = GT) then bigok := true;
    if (not smallok) and (REALCOMPARE(a, PARAMETERS.AREA2) = LT) then smallok := true;
    if bigok and smallok then begin lic15 := true; exit; end;
  end;
end;

procedure compute_cmv;
begin
  CMV[1]  := lic1;
  CMV[2]  := lic2;
  CMV[3]  := lic3;
  CMV[4]  := lic4;
  CMV[5]  := lic5;
  CMV[6]  := lic6;
  CMV[7]  := lic7;
  CMV[8]  := lic8;
  CMV[9]  := lic9;
  CMV[10] := lic10;
  CMV[11] := lic11;
  CMV[12] := lic12;
  CMV[13] := lic13;
  CMV[14] := lic14;
  CMV[15] := lic15;
end;

procedure build_pum;
var i, j: integer;
begin
  for i := Low(CMV) to High(CMV) do begin
    for j := Low(CMV) to High(CMV) do begin
      if i = j then continue; {leave diagonal as provided}
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := true;
        ANDD   : PUM[i, j] := CMV[i] and CMV[j];
        ORR    : PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;
end;

procedure build_fuv_and_decide;
var i, j: integer; alltrue: boolean;
begin
  for i := Low(FUV) to High(FUV) do begin
    if not PUM[i, i] then begin
      FUV[i] := true;
    end else begin
      alltrue := true;
      for j := Low(PUM) to High(PUM) do begin
        if not PUM[i, j] then begin
          alltrue := false; break;
        end;
      end;
      FUV[i] := alltrue;
    end;
  end;

  LAUNCH := true;
  for i := Low(FUV) to High(FUV) do begin
    if not FUV[i] then begin LAUNCH := false; break; end;
  end;
end;

procedure DECIDE;
begin
  compute_cmv;
  build_pum;
  build_fuv_and_decide;
end;

end.
